INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2024/06/15 15:00:00", -470.0, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 4, 5, 2002, 4, 130503, "ホウオウ", 0.0, 10019, "2024/09/22 14:59:59", 3);
