INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2024/06/15 15:00:00", -470.0, 4.8, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2, 5, 2002, 1, 123301, "ネア", 0.0, 10021, "2024/09/22 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2024/09/15 15:00:00", -470.0, 4.922, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 1, 6, 2002, 3, 133301, "カリザ", 0.0, 10022, "2024/12/22 14:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2024/09/15 15:00:00", -470.0, 9.638, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 5, 6, 2002, 3, 133301, "カリザ", 0.0, 10023, "2024/12/22 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2024/09/15 15:00:00", -470.0, 2.88, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2, 6, 2002, 1, 133401, "ミーア", 0.0, 10024, "2024/12/22 14:59:59", 1);
