INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/03/15 15:00:00", -470.0, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 1, 8, 2002, 2, 137001, "デュラン", 0.0, 10033, "2025/06/23 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/06/16 15:00:00", -470.0, 0.0, "おう\n好きなもん持ってきな", 2, 9, 2002, 2, 135902, "サツキ", 0.0, 10034, "2025/09/23 14:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/06/16 15:00:00", -470.0, 4.935, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 6, 9, 2002, 1, 135902, "サツキ", 0.0, 10035, "2025/09/23 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/06/16 15:00:00", -470.0, 7.441, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 5, 9, 2002, 2, 135802, "ユキノ", 0.0, 10036, "2025/09/23 14:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/06/16 15:00:00", -470.0, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 7, 9, 2002, 7, 135802, "ユキノ", 0.0, 10037, "2025/09/23 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/09/16 15:00:00", -470.0, 2.295, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2, 10, 2002, 2, 130901, "クルル", 0.0, 10038, "2025/12/22 14:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/09/16 15:00:00", -470.0, 6.281, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 6, 10, 2002, 1, 130901, "クルル", 0.0, 10039, "2025/12/22 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/09/16 15:00:00", -470.0, 5.549, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 1, 10, 2002, 2, 137701, "ヴォルガーノ", 0.0, 10040, "2025/12/22 14:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/09/16 15:00:00", -470.0, 2.64, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 6, 10, 2002, 3, 137701, "ヴォルガーノ", 0.0, 10041, "2025/12/22 14:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/12/15 15:00:00", -470.0, 7.642, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 4, 11, 2002, 7, 132801, "ライラエル", 0.0, 10042, "2026/03/23 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/12/15 15:00:00", -470.0, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 1, 11, 2002, 1, 132802, "ライラエル", 0.0, 10043, "2026/03/23 11:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/12/15 15:00:00", -470.0, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 1, 11, 2002, 1, 134502, "クローチェ", 0.0, 10044, "2026/03/23 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2025/12/15 15:00:00", -470.0, 3.72, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 1, 11, 2002, 2, 134501, "クローチェ", 0.0, 10045, "2026/03/23 11:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/03/16 12:00:00", -470.0, 4.991, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 1, 12, 2002, 2, 138201, "ネフィ＝ネラ", 0.0, 10046, "2026/06/22 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/03/16 12:00:00", -470.0, 3.877, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 4, 12, 2002, 1, 138201, "ネフィ＝ネラ", 0.0, 10047, "2026/06/22 11:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/03/16 12:00:00", -470.0, 1.71, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 6, 12, 2002, 4, 136001, "アラクネ", 0.0, 10048, "2026/06/22 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/03/16 12:00:00", -470.0, 5.32, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2, 12, 2002, 5, 136001, "アラクネ", 0.0, 10049, "2026/06/22 11:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/06/15 12:00:00", -470.0, 3.727, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 4, 13, 2002, 9, 135401, "アネモネ", 0.0, 10050, "2026/09/22 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/06/15 12:00:00", -470.0, 7.213, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 9, 13, 2002, 7, 135401, "アネモネ", 0.0, 10051, "2026/09/22 11:59:59", 2);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/06/15 12:00:00", -470.0, 1.874, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 2, 13, 2002, 1, 135301, "クリア", 0.0, 10052, "2026/09/22 11:59:59", 1);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("2026/06/15 12:00:00", -470.0, 0.0, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 2, 13, 2002, 2, 135301, "クリア", 0.0, 10053, "2026/09/22 11:59:59", 2);
